// Technical Practice Flashcards — Investment Banking (500 Questions)
export type Flashcard = { q: string; a: string; category: string; firm?: string; difficulty?: 'Easy' | 'Medium' | 'Hard' };

export const IB_FLASHCARDS: Flashcard[] = [
// ═══ ACCOUNTING & FINANCIAL STATEMENTS (1-80) ═══
{q:"Walk through the three core financial statements and explain the main purpose of each.",a:"The income statement shows revenue, expenses, and net income over a period — it measures profitability. The balance sheet shows assets, liabilities, and equity at a point in time — it measures financial position. The cash flow statement reconciles net income to actual cash generated across operating, investing, and financing activities.",category:"Accounting",firm:"Goldman Sachs, Morgan Stanley",difficulty:"Easy"},
{q:"How do the three financial statements connect to each other in a fully integrated model?",a:"Net income from the IS flows into retained earnings on the BS and is the starting point for CFO on the CFS. D&A from the IS is added back on the CFS and reduces PP&E on the BS. CapEx on the CFS increases PP&E on the BS. Debt issuance/repayment on CFS changes debt on the BS. Ending cash on the CFS ties to cash on the BS.",category:"Accounting",firm:"J.P. Morgan, Evercore",difficulty:"Medium"},
{q:"If you could review only one financial statement to assess a business, which would you choose and why?",a:"The cash flow statement, because it shows actual cash generated and spent regardless of accounting choices. It reveals whether the business converts profits to cash, how much it reinvests, and how it finances itself. You can also reverse-engineer approximate income and balance sheet positions from it.",category:"Accounting",firm:"Centerview Partners",difficulty:"Medium"},
{q:"If allowed two financial statements, which combination would you select and how would you recreate the third?",a:"Income statement and balance sheet. From two consecutive balance sheets you can derive the change in cash (top of CFS), and from the IS you get net income and non-cash items. Working capital changes come from BS deltas. CapEx approximated from PP&E changes plus depreciation. Financing flows from debt and equity changes.",category:"Accounting",firm:"PJT Partners, Lazard",difficulty:"Hard"},
{q:"A company records an additional 20 in depreciation. Walk through the impact on all three statements.",a:"IS: D&A +20, pre-tax income −20, taxes −5 (at 25%), net income −15. CFS: NI −15, add back D&A +20, net cash +5. BS: Cash +5, PP&E −20, total assets −15. Retained earnings −15, so both sides down 15.",category:"Accounting",firm:"Bank of America, Barclays",difficulty:"Hard"},
{q:"If depreciation increases by 15 and the tax rate is 25, how does this affect net income and cash flow?",a:"Pre-tax income falls by 15, tax savings of 3.75, so net income decreases by 11.25. On the CFS, NI −11.25 plus D&A add-back +15 = net cash increase of 3.75 (the tax shield).",category:"Accounting",firm:"Citi, Deutsche Bank",difficulty:"Medium"},
{q:"Why does a non-cash expense like depreciation increase cash flow from operations?",a:"Depreciation reduces taxable income without requiring a cash outflow. The resulting tax savings is real cash kept by the company. On the CFS, depreciation is added back to net income because it was deducted on the IS but no cash left the business.",category:"Accounting",firm:"UBS, Jefferies",difficulty:"Easy"},
{q:"Where can depreciation appear on the income statement, and why might presentation differ by company?",a:"It can appear as a separate line item, embedded within COGS (for manufacturing equipment), or within SG&A (for office assets). Presentation depends on the nature of the depreciated assets and industry conventions. Analysts must check the CFS or notes to find total D&A.",category:"Accounting",firm:"Houlihan Lokey",difficulty:"Medium"},
{q:"A 25 increase in accrued expenses is being recognized as an expense. Walk through the impact on the three statements.",a:"IS: Operating expense +25, tax savings 6.25, NI −18.75. CFS: NI −18.75, accrued liabilities increase is a source of cash +25, net cash +6.25. BS: Cash +6.25, accrued liabilities +25, retained earnings −18.75. Both sides balance.",category:"Accounting",firm:"Goldman Sachs, Moelis & Co.",difficulty:"Hard"},
{q:"Inventory rises by 30, paid in cash, and no inventory has yet been sold. What happens to each statement?",a:"IS: No impact — inventory is not expensed until sold as COGS. CFS: Inventory increase is a use of cash in working capital, cash −30. BS: Cash −30, inventory +30. Total assets unchanged. No P&L or equity impact.",category:"Accounting",firm:"Morgan Stanley, RBC Capital Markets",difficulty:"Medium"},
{q:"Why does a change in inventory not immediately affect the income statement?",a:"Inventory is an asset on the balance sheet until it is sold. Only when inventory is sold does the cost transfer to COGS on the income statement. This follows the matching principle — expenses are recognized in the same period as the associated revenue.",category:"Accounting",firm:"J.P. Morgan",difficulty:"Easy"},
{q:"A company issues 200 of new term debt to fund 200 of new PP&E. Show the impact at close on the three statements.",a:"IS: No immediate impact. CFS: Debt issuance +200 in financing, CapEx −200 in investing, net cash zero. BS: PP&E +200, debt +200. Assets and liabilities both up 200. No equity change.",category:"Accounting",firm:"Wells Fargo Securities, Barclays",difficulty:"Medium"},
{q:"One year later, that 200 of PP&E is depreciated straight-line over 10 years; the debt pays 8% cash interest, with no principal amortization. Show the Year 1 impact.",a:"IS: D&A −20, interest −16, pre-tax income −36, taxes −9, NI −27. CFS: NI −27, add back D&A +20, cash −7. BS: Cash −7, PP&E −20. Debt unchanged. RE −27. Assets down 27, equity down 27.",category:"Accounting",firm:"Evercore, Centerview Partners",difficulty:"Hard"},
{q:"In Year 3 the undepreciated PP&E is written down to zero and the remaining debt is repaid in full. How do the three statements change in that year?",a:"IS: Impairment charge for remaining book value (200−60=140), plus final year interest 16, pre-tax loss 156, tax benefit 39, NI −117. CFS: NI −117, add back impairment 140, add back D&A 20 (if taken), debt repayment −200, significant cash outflow. BS: PP&E goes to zero, debt goes to zero, cash decreases significantly, RE drops by NI.",category:"Accounting",firm:"Lazard, PJT Partners",difficulty:"Hard"},
{q:"A company purchases 40 of raw materials inventory that will be manufactured and sold later. Describe the timing of when costs appear on the income statement.",a:"At purchase, 40 moves from cash to raw materials inventory — no IS impact. During manufacturing, costs transfer to work-in-progress, still no IS impact. Only when finished goods are sold does the cost appear as COGS on the IS, matched against the revenue from that sale.",category:"Accounting",firm:"Piper Sandler",difficulty:"Medium"},
{q:"The company sells finished goods for 100 in revenue and 60 of cost that was previously inventory. Walk through the three statements.",a:"IS: Revenue +100, COGS +60, gross profit +40, taxes +10, NI +30. CFS: NI +30, inventory decrease +60, but if sold on credit AR increases −100, net depends on cash vs credit. If all cash: cash +90 after tax. BS: Cash up, inventory −60, RE +30.",category:"Accounting",firm:"Goldman Sachs, William Blair",difficulty:"Hard"},
{q:"Under what scenarios can shareholders' equity become negative? What does that signal?",a:"Large accumulated losses exceeding paid-in capital, massive share buybacks funded by debt, or large impairment charges. It signals the company has returned or lost more value than shareholders originally invested. Common in highly leveraged companies or those with persistent losses.",category:"Accounting",firm:"Moelis & Co., Guggenheim Securities",difficulty:"Medium"},
{q:"Define working capital in a simple way and explain why it matters in valuation.",a:"Working capital is current operating assets (AR, inventory) minus current operating liabilities (AP, accrued expenses), excluding cash and debt. It matters because changes in WC consume or release cash, directly affecting free cash flow and therefore valuation in a DCF.",category:"Accounting",firm:"Morgan Stanley, Evercore",difficulty:"Easy"},
{q:"What does a consistently negative working capital position indicate about a business model?",a:"The company collects cash from customers before paying suppliers — it's funded by its operations. Common in subscription businesses, retailers with fast inventory turns, and companies with strong bargaining power. It's generally a positive sign of cash flow efficiency.",category:"Accounting",firm:"Centerview Partners",difficulty:"Medium"},
{q:"What is operating working capital and why do bankers prefer it to total working capital in models?",a:"Operating working capital excludes cash, short-term debt, and current portion of long-term debt — focusing only on trade-related items like AR, inventory, AP, and accrued expenses. Bankers prefer it because cash and debt are treated separately in enterprise value calculations and capital structure analysis.",category:"Accounting",firm:"J.P. Morgan, Lazard",difficulty:"Medium"},
{q:"A company records a 120 impairment on an intangible asset. How does this flow through the three statements?",a:"IS: Impairment charge −120, tax benefit +30 (at 25%), NI −90. CFS: NI −90, add back non-cash impairment +120, net cash +30. BS: Cash +30, intangible asset −120, RE −90. Total assets −90, equity −90.",category:"Accounting",firm:"Bank of America, Rothschild",difficulty:"Hard"},
{q:"Explain the difference between an impairment charge and regular depreciation or amortization.",a:"D&A is systematic allocation of an asset's cost over its useful life — predictable and planned. Impairment is an unplanned write-down when the asset's fair value drops below its carrying value, reflecting a sudden loss of value. Impairment is typically non-recurring; D&A is recurring.",category:"Accounting",firm:"Deutsche Bank, UBS",difficulty:"Easy"},
{q:"How does a 150 equity injection from a new investor affect the three statements at closing?",a:"IS: No impact. CFS: Financing inflow +150. BS: Cash +150, common stock and/or APIC +150. Assets and equity both increase by 150. No debt or P&L effect.",category:"Accounting",firm:"Jefferies",difficulty:"Easy"},
{q:"A government injects 300 of equity into a distressed bank. Walk through the accounting.",a:"IS: No immediate impact (equity injection is not revenue). CFS: Financing inflow +300. BS: Cash +300, equity +300 (in common stock, preferred stock, or APIC depending on instrument). This recapitalizes the bank and may improve capital ratios.",category:"Accounting",firm:"Goldman Sachs, Citi",difficulty:"Medium"},
{q:"A lender forgives 80 of outstanding debt principal. Describe the impact on the financial statements.",a:"IS: Gain on debt extinguishment +80, taxes +20, NI +60. CFS: NI +60, subtract non-cash gain −80, net cash −20 (just the tax payment). BS: Cash −20, debt −80, RE +60. Equity increases, leverage decreases.",category:"Accounting",firm:"Houlihan Lokey, PJT Partners",difficulty:"Hard"},
{q:"What is deferred tax, and how can it arise in a transaction or modeling context?",a:"Deferred tax arises from timing differences between book and tax treatment. A DTL means you owe taxes later (e.g., accelerated tax depreciation vs straight-line book). A DTA means future tax benefits (e.g., NOLs). In M&A, asset step-ups create DTLs as the new tax basis differs from book.",category:"Accounting",firm:"Evercore, Morgan Stanley",difficulty:"Medium"},
{q:"How do deferred tax liabilities typically get created on an acquisition balance sheet?",a:"When purchase price allocation steps up asset values above their tax basis, the difference creates a DTL. The acquirer will depreciate/amortize at the higher book value but can only deduct the lower tax basis, creating a future tax obligation.",category:"Accounting",firm:"Centerview Partners, J.P. Morgan",difficulty:"Hard"},
{q:"Why might a deferred tax asset be impaired following an acquisition?",a:"If the target has NOLs or other DTAs, Section 382 limitations may restrict annual usage post-acquisition. If the acquirer cannot realize the full benefit, the DTA must be written down. Also, a change in control may trigger valuation allowances if future profitability is uncertain.",category:"Accounting",firm:"Lazard, Rothschild",difficulty:"Hard"},
{q:"A company changes its revenue recognition policy to earlier recognition. What are some likely effects on the statements over time?",a:"Initially: higher revenue and NI, but AR increases faster (recognized revenue not yet collected). Over time the effect normalizes. Cash flow may not change much since actual collections are unchanged. Could inflate current-period metrics but creates a pull-forward effect.",category:"Accounting",firm:"Barclays, Goldman Sachs",difficulty:"Medium"},
{q:"Explain the difference between cash and accrual accounting, and why accrual is standard for corporate analysis.",a:"Cash accounting records transactions when cash moves. Accrual records revenue when earned and expenses when incurred, regardless of cash timing. Accrual is standard because it better matches economic activity to the period it occurs, giving a more accurate picture of performance.",category:"Accounting",firm:"Piper Sandler, RBC Capital Markets",difficulty:"Easy"},
{q:"Under what conditions would capitalizing an expenditure be more appropriate than expensing it?",a:"When the expenditure provides economic benefit beyond the current period — such as purchasing equipment, building a factory, or developing software with multi-year utility. The cost is spread over the asset's useful life via depreciation or amortization rather than hitting the IS immediately.",category:"Accounting",firm:"William Blair",difficulty:"Easy"},
{q:"Give examples of line items that are typically capitalized and amortized rather than expensed immediately.",a:"PP&E (depreciated), patents and trademarks (amortized), capitalized software development costs, leasehold improvements, deferred financing costs, and certain R&D costs under IFRS when technical feasibility is demonstrated.",category:"Accounting",firm:"Bank of America",difficulty:"Easy"},
{q:"What does an increase in other current assets often represent, and how would you treat it in a model?",a:"Often represents prepaid expenses, tax receivables, or other short-term items. In a model, you'd typically project it as a percentage of revenue or hold it flat. An increase is a use of cash in working capital on the CFS.",category:"Accounting",firm:"Deutsche Bank",difficulty:"Easy"},
{q:"How would you interpret a materially large goodwill balance on a company's balance sheet?",a:"It indicates the company has made significant acquisitions and paid premiums above the fair value of identifiable net assets. A large goodwill balance means future impairment risk if acquired businesses underperform, and it inflates total assets without generating direct cash flows.",category:"Accounting",firm:"Morgan Stanley, Citi",difficulty:"Medium"},
{q:"When might you see goodwill decrease over time without any obvious acquisition or divestiture activity?",a:"Goodwill impairment testing. If the reporting unit's fair value falls below its carrying value, goodwill must be written down. This can happen due to deteriorating business conditions, lower earnings expectations, or market declines that reduce the implied value of past acquisitions.",category:"Accounting",firm:"Evercore",difficulty:"Medium"},
{q:"Explain what retained earnings represent and list the main drivers of changes in this line item.",a:"Retained earnings is the cumulative net income minus cumulative dividends paid since inception. It increases with net income and decreases with dividends, share buybacks charged to RE, and comprehensive losses. It's the primary link between the IS and the equity section of the BS.",category:"Accounting",firm:"J.P. Morgan",difficulty:"Easy"},
{q:"Why might a profitable company still show negative operating cash flow in a given period?",a:"Large working capital investments (AR buildup, inventory buildup), significant one-time cash payments (taxes, settlements), or rapid growth requiring upfront cash outlays. Revenue is recognized but cash hasn't been collected, or cash expenses exceed accrual-based expenses.",category:"Accounting",firm:"Goldman Sachs, Moelis & Co.",difficulty:"Medium"},
{q:"Why might a company with net losses still generate positive operating cash flow?",a:"Large non-cash charges like D&A, impairments, or stock-based compensation reduce net income without using cash. Favorable working capital changes (collecting AR, deferring payments) also boost cash. The operating cash flow adds back these non-cash items.",category:"Accounting",firm:"Jefferies, Wells Fargo Securities",difficulty:"Medium"},
{q:"What is the difference between accounts payable and accrued expenses?",a:"AP represents amounts owed for goods/services already invoiced by suppliers — there's a specific invoice. Accrued expenses represent obligations incurred but not yet invoiced — like wages earned but unpaid, or utilities consumed but not billed. Both are current liabilities.",category:"Accounting",firm:"Barclays",difficulty:"Easy"},
{q:"How does the choice of depreciation method (straight-line vs. accelerated) affect financial statements over the life of an asset?",a:"Accelerated front-loads depreciation expense, reducing NI and taxes early but boosting them later. Straight-line spreads evenly. Over the asset's full life, total depreciation and total tax are the same — it's a timing difference. Accelerated is better for cash flow early on due to tax deferral.",category:"Accounting",firm:"UBS, Piper Sandler",difficulty:"Medium"},
{q:"Explain how stock-based compensation flows through the three financial statements.",a:"IS: SBC is an operating expense reducing NI. CFS: Added back as a non-cash expense in CFO. BS: APIC increases in equity (offsetting the expense). Diluted share count increases when options/RSUs vest. SBC is real economic cost through dilution even though it's non-cash.",category:"Accounting",firm:"Goldman Sachs, Morgan Stanley",difficulty:"Medium"},
{q:"A company issues 50 of new common shares at par to employees as compensation. How does this affect each statement?",a:"IS: SBC expense −50, tax benefit +12.5, NI −37.5. CFS: NI −37.5, add back non-cash SBC +50, net cash +12.5. BS: Cash +12.5, common stock/APIC +50, RE −37.5, net equity +12.5. Share count increases.",category:"Accounting",firm:"Centerview Partners",difficulty:"Hard"},
{q:"How do you treat operating leases versus finance leases on the statements, and why does it matter in valuation?",a:"Under ASC 842, both go on the BS as right-of-use asset and lease liability. Finance leases: front-loaded expense (interest + amortization). Operating leases: straight-line rent expense. In valuation, you must decide whether to treat lease liabilities as debt (adding to EV) and adjust EBITDA accordingly for consistency.",category:"Accounting",firm:"Lazard, J.P. Morgan",difficulty:"Hard"},
{q:"What is the impact of increasing days sales outstanding (DSO) on cash flow and working capital?",a:"Rising DSO means customers are taking longer to pay. AR grows faster than revenue, consuming cash. Working capital increases, reducing free cash flow. It can signal collection problems, more lenient credit terms, or revenue recognition issues.",category:"Accounting",firm:"Bank of America",difficulty:"Medium"},
{q:"If a company starts offering more generous payment terms to customers, what working capital changes would you expect?",a:"AR would increase as customers take longer to pay. DSO rises. This is a use of cash in working capital, reducing FCF. Revenue might increase if the terms attract more customers, but the cash conversion cycle lengthens.",category:"Accounting",firm:"RBC Capital Markets",difficulty:"Medium"},
{q:"How do you estimate maintenance capex versus growth capex from disclosures or limited data?",a:"Maintenance CapEx approximates depreciation (replacing existing assets). Growth CapEx is total CapEx minus maintenance. Some companies disclose the split. Otherwise, use D&A as a proxy for maintenance, or compare CapEx to revenue growth — if CapEx grows faster, the excess is likely growth-related.",category:"Accounting",firm:"Evercore, Moelis & Co.",difficulty:"Medium"},
{q:"What might you infer if a company's capital expenditures are consistently below its depreciation expense?",a:"The company is underinvesting in its asset base — spending less on replacement than assets are wearing out. Short-term this boosts FCF, but long-term it may signal deteriorating competitive position, aging infrastructure, or an asset-light transition.",category:"Accounting",firm:"Morgan Stanley",difficulty:"Medium"},
{q:"How would you treat restructuring charges in your analysis of a company's normalized earnings power?",a:"Add them back to calculate normalized EBITDA since they're non-recurring. But scrutinize frequency — if a company takes restructuring charges every year, they may be a real cost of doing business and shouldn't be fully added back.",category:"Accounting",firm:"Houlihan Lokey, Rothschild",difficulty:"Medium"},
{q:"When might it be appropriate to adjust EBITDA for stock-based compensation in valuation work?",a:"SBC is a real economic cost (dilution) so many argue it shouldn't be added back. However, since it's non-cash and doesn't affect debt capacity, some LBO models and credit analyses add it back. The key is consistency — if you add it back, use higher diluted share counts.",category:"Accounting",firm:"Goldman Sachs, Centerview Partners",difficulty:"Medium"},
{q:"What are the implications if a company repeatedly records large one-time charges?",a:"If one-time charges recur, they're not truly one-time — they represent a real cost of doing business. Analysts should be skeptical of adjusted metrics that exclude them. It may indicate poor acquisitions, operational problems, or aggressive accounting to inflate adjusted earnings.",category:"Accounting",firm:"J.P. Morgan, PJT Partners",difficulty:"Medium"},
{q:"Explain the concept of minority interest and where it appears on the statements.",a:"Minority interest (non-controlling interest) represents outside ownership in a subsidiary the parent consolidates at 100%. On the IS, minority interest's share of NI is subtracted. On the BS, it appears in equity. In EV, it's added because the parent consolidates 100% of revenue/EBITDA.",category:"Accounting",firm:"Lazard, Morgan Stanley",difficulty:"Medium"},
{q:"How do you adjust enterprise value for non-controlling interests, and why?",a:"Add NCI to EV because the parent consolidates 100% of the subsidiary's revenue and EBITDA, but doesn't own 100% of the equity. Adding NCI ensures the numerator (EV) matches the denominator (full EBITDA) in valuation multiples.",category:"Accounting",firm:"Evercore, Bank of America",difficulty:"Medium"},
{q:"What is the difference between non-controlling interest and equity-method investments in another company?",a:"NCI: parent owns >50%, consolidates 100% of subsidiary's financials, NCI represents the outside minority. Equity method: parent owns 20-50%, records its proportional share of the investee's NI as a single line item. The investee's full financials are NOT consolidated.",category:"Accounting",firm:"Goldman Sachs",difficulty:"Medium"},
{q:"Why is interest income often classified below operating income in an income statement?",a:"Interest income comes from cash/investments, not core operations. Separating it from operating income gives a cleaner view of the business's operational profitability. It also aligns with the EV framework where operating metrics are capital-structure neutral.",category:"Accounting",firm:"Citi",difficulty:"Easy"},
{q:"How would capitalizing interest during construction of an asset affect the statements?",a:"IS: No interest expense during construction (capitalized instead), so higher NI. BS: PP&E increases by the capitalized interest. CFS: Higher NI but reclassified — the interest becomes part of CapEx (investing) rather than CFO. Total cash impact is the same, but reported metrics differ.",category:"Accounting",firm:"Deutsche Bank, UBS",difficulty:"Hard"},
{q:"A company sells an asset for 70 that has a book value of 50. Walk through the three statements.",a:"IS: Gain on sale +20, taxes +5, NI +15. CFS: NI +15, subtract gain (non-operating) −20, proceeds from sale +70 in CFI, net cash +65. BS: Cash +65, asset (PP&E) −50, RE +15. Assets net +15, equity +15.",category:"Accounting",firm:"Barclays, Jefferies",difficulty:"Hard"},
{q:"How would you detect aggressive revenue recognition practices using the three statements over multiple periods?",a:"Look for: revenue growing faster than cash collections (rising DSO), declining cash conversion, increasing gap between NI and CFO, growing deferred revenue or unbilled receivables, and revenue spikes at quarter-end. Compare revenue trends to industry peers and operational metrics.",category:"Accounting",firm:"Morgan Stanley, Rothschild",difficulty:"Hard"},
{q:"Why might you reclassify certain other income or other expense items when normalizing earnings?",a:"To separate recurring operating performance from non-recurring or non-operating items (FX gains/losses, asset sales, litigation settlements). This gives a cleaner view of sustainable earnings power for valuation and comparability purposes.",category:"Accounting",firm:"Centerview Partners",difficulty:"Medium"},
{q:"Explain the difference between cash taxes paid and income tax expense on the income statement.",a:"Income tax expense is the accrual-based GAAP provision, including current and deferred portions. Cash taxes paid is the actual cash outflow to tax authorities. They differ due to timing differences (deferred taxes), NOL utilization, tax credits, and refunds.",category:"Accounting",firm:"PJT Partners",difficulty:"Medium"},
{q:"A company's effective tax rate diverges meaningfully from the statutory rate. What might cause that?",a:"International operations with different tax rates, R&D tax credits, non-deductible expenses (goodwill impairment, certain SBC), tax-exempt income, NOL utilization, valuation allowances on DTAs, or permanent differences between book and tax treatment.",category:"Accounting",firm:"Goldman Sachs, J.P. Morgan",difficulty:"Medium"},
{q:"How does a share repurchase affect earnings per share and book value per share?",a:"EPS increases because the denominator (share count) decreases while NI is roughly the same (slightly lower due to lost interest on cash used). Book value per share may increase or decrease depending on whether shares were repurchased above or below book value.",category:"Accounting",firm:"Morgan Stanley, Citi",difficulty:"Medium"},
{q:"What are the accounting implications of a stock split versus a stock dividend?",a:"Stock split: shares multiply, par value adjusts proportionally, no journal entry needed — just a memo. Stock dividend: new shares issued, retained earnings decreases, common stock/APIC increases. Both increase share count but a stock dividend transfers value within equity accounts.",category:"Accounting",firm:"Bank of America",difficulty:"Easy"},
{q:"A company issues convertible debt. How is it reflected on the balance sheet at issuance?",a:"Under US GAAP (ASU 2020-06), convertible debt is generally recorded entirely as a liability at face value. Under older rules, it was bifurcated into debt and equity components. The conversion feature may require separate accounting depending on the specific terms.",category:"Accounting",firm:"Lazard, Guggenheim Securities",difficulty:"Hard"},
{q:"When would you apply the if-converted method versus the treasury stock method for EPS?",a:"If-converted: used for convertible securities — assume all converted, add back interest savings to NI, increase share count. Treasury stock method: used for options/warrants — assume exercised, proceeds used to buy back shares at market price, net dilution added to shares.",category:"Accounting",firm:"Evercore, Goldman Sachs",difficulty:"Hard"},
{q:"How do you estimate fully diluted shares outstanding from a capitalization table?",a:"Start with basic shares outstanding. Add net dilution from in-the-money options/warrants using treasury stock method. Add shares from RSU vesting. Add potential shares from convertible securities using if-converted method (if dilutive). Exclude out-of-the-money instruments.",category:"Accounting",firm:"J.P. Morgan, Centerview Partners",difficulty:"Medium"},
{q:"How would you reconcile net income to operating cash flow starting from the income statement?",a:"Start with NI. Add back non-cash charges (D&A, SBC, impairments, deferred taxes). Subtract non-cash gains. Adjust for working capital changes: subtract increases in AR/inventory, add increases in AP/accrued liabilities. Add back other non-operating items to arrive at CFO.",category:"Accounting",firm:"Morgan Stanley",difficulty:"Medium"},
{q:"Why might you adjust reported EBITDA for unusual or non-recurring items in a sell-side process?",a:"To present normalized earnings power — showing what the business earns on a sustainable, run-rate basis. Buyers want to pay for recurring profitability, not one-time charges or windfalls. Common adjustments: restructuring, litigation, M&A costs, one-time revenue items.",category:"Accounting",firm:"Houlihan Lokey, Moelis & Co.",difficulty:"Medium"},
{q:"Describe how changes in provisions or reserves affect the three statements.",a:"Creating a provision: IS expense increases, NI decreases. BS: provision (liability) increases, RE decreases. CFS: add back non-cash provision. When the provision is used (cash paid): no IS impact, BS: provision decreases, cash decreases. CFS: cash outflow in operating.",category:"Accounting",firm:"Rothschild, Barclays",difficulty:"Hard"},
{q:"What does a growing deferred revenue balance tell you about a company's business model?",a:"The company is collecting cash before delivering services — a sign of strong demand and subscription/prepayment-based revenue. It's a positive working capital dynamic. However, it also represents an obligation to deliver, so quality and sustainability matter.",category:"Accounting",firm:"Goldman Sachs",difficulty:"Easy"},
{q:"How would you treat deferred revenue when estimating free cash flow?",a:"Increases in deferred revenue add to CFO (cash collected but not yet recognized as revenue). In a DCF, this is captured in working capital changes. For normalized FCF, consider whether deferred revenue growth is sustainable or a one-time catch-up.",category:"Accounting",firm:"Morgan Stanley, Piper Sandler",difficulty:"Medium"},
{q:"A company reclassifies a portion of long-term debt as current. How does that impact your analysis?",a:"Working capital deteriorates (current liabilities increase). Current ratio and quick ratio decline. It signals upcoming refinancing need or maturity wall. In EV calculations, the debt treatment doesn't change, but liquidity analysis becomes more important.",category:"Accounting",firm:"J.P. Morgan",difficulty:"Medium"},
{q:"How do you account for pension obligations and why are they important in valuation?",a:"Pension obligations appear as a liability (PBO minus plan assets = funded status). Underfunded pensions are debt-like obligations that should be considered in EV. Pension expense appears on the IS. Changes in actuarial assumptions can materially swing the liability and affect equity.",category:"Accounting",firm:"Lazard, Deutsche Bank",difficulty:"Hard"},
{q:"What are the key differences between IFRS and US GAAP that matter most for banking analysis?",a:"Revenue recognition (timing differences), lease accounting (converging but nuances remain), inventory (LIFO allowed under GAAP, not IFRS), R&D capitalization (more common under IFRS), goodwill (IFRS amortizes in some jurisdictions), and financial instruments classification.",category:"Accounting",firm:"UBS, Rothschild",difficulty:"Medium"},
{q:"A company capitalizes R&D while peers expense it. How would you adjust to make metrics comparable?",a:"Expense the capitalized R&D in the period incurred to match peers. This reduces NI and EBITDA. Remove the amortization of previously capitalized R&D from the IS. Remove the capitalized asset from the BS. This normalizes margins and returns across the comp set.",category:"Accounting",firm:"Centerview Partners, Evercore",difficulty:"Hard"},
{q:"How would you adjust a company's financials to evaluate its performance excluding foreign exchange volatility?",a:"Use constant-currency analysis: apply prior-period exchange rates to current-period foreign revenues and costs. Many companies disclose organic/constant-currency growth in press releases. This isolates true operational performance from FX translation effects.",category:"Accounting",firm:"Goldman Sachs",difficulty:"Medium"},
{q:"Why does goodwill not amortize under US GAAP, and how is impairment tested conceptually?",a:"FASB determined goodwill has an indefinite life, so systematic amortization isn't appropriate. Instead, companies test annually (or when triggers arise) by comparing reporting unit fair value to carrying value. If carrying value exceeds fair value, goodwill is impaired by the difference.",category:"Accounting",firm:"J.P. Morgan, Morgan Stanley",difficulty:"Medium"},
{q:"What are the practical modeling implications of a company with large off-balance sheet guarantees?",a:"They represent contingent liabilities that could become real obligations. You may need to adjust EV to reflect the risk, apply probability-weighted liability estimates in scenarios, or note them as risk factors. Lenders and rating agencies treat them as quasi-debt.",category:"Accounting",firm:"PJT Partners",difficulty:"Hard"},
{q:"How can you use the cash flow statement to evaluate the quality of a company's earnings?",a:"Compare CFO to NI — if CFO consistently exceeds NI, earnings quality is high (cash-backed). If NI exceeds CFO, earnings may be inflated by accruals. Check for large non-cash add-backs, working capital deterioration, and whether CapEx matches depreciation.",category:"Accounting",firm:"Evercore, Lazard",difficulty:"Medium"},
{q:"Describe a situation where the cash flow statement looks strong but the business is actually deteriorating.",a:"A company delays paying suppliers (AP increases), draws down inventory without replenishing, or collects prepayments for services it may not deliver. These boost short-term CFO but mask declining revenue, margin erosion, or unsustainable working capital harvesting.",category:"Accounting",firm:"Houlihan Lokey, Rothschild",difficulty:"Hard"},
{q:"Describe a situation where the income statement looks weak but the underlying cash generation is attractive.",a:"Heavy D&A or amortization of intangibles from past acquisitions depresses NI, but the business generates strong operating cash flow since those are non-cash charges. Also, restructuring charges may temporarily depress earnings while the underlying business is healthy.",category:"Accounting",firm:"Moelis & Co., Goldman Sachs",difficulty:"Hard"},
// ═══ VALUATION & DCF (81-170) ═══
{q:"List the main valuation methodologies used in investment banking and briefly define each.",a:"1) DCF: intrinsic value from discounted projected cash flows. 2) Trading Comps: relative value from public peer multiples. 3) Precedent Transactions: value implied by past M&A deal multiples. 4) LBO Analysis: value based on sponsor return requirements. 5) Sum-of-Parts: segment-level valuation for diversified companies.",category:"Valuation",firm:"Goldman Sachs, Morgan Stanley, J.P. Morgan",difficulty:"Easy"},
{q:"In what situations would you favor a DCF over a multiples-based valuation and vice versa?",a:"DCF when the company has predictable cash flows, unique characteristics making comps imperfect, or when you want to test specific assumptions. Comps when there are good public peers, the company lacks reliable projections, or for quick market-based sanity checks.",category:"Valuation",firm:"Evercore, Centerview Partners",difficulty:"Medium"},
{q:"Why is an intrinsic valuation often more sensitive to assumptions than a trading comparables analysis?",a:"A DCF depends on projected growth, margins, CapEx, WACC, and terminal value — small changes in any compound over time. Comps anchor to market prices and peer multiples, which embed collective expectations. The DCF's sensitivity to terminal assumptions alone can swing value 20-30%.",category:"Valuation",firm:"Lazard, PJT Partners",difficulty:"Medium"},
{q:"When screening for trading comparables, what are the typical quantitative and qualitative filters you apply?",a:"Quantitative: similar size (revenue/market cap), growth rates, margins, capital intensity. Qualitative: same industry/sub-sector, business model, end markets, geographic mix, and stage of lifecycle. No comp set is perfect — judgment is key.",category:"Valuation",firm:"Goldman Sachs, Bank of America",difficulty:"Easy"},
{q:"How do you decide which multiples are most relevant for a particular industry?",a:"Match the multiple to what drives value in that sector. Capital-light tech: EV/Revenue or EV/EBITDA. Capital-intensive industrials: EV/EBIT (captures D&A). Banks: P/TBV, P/E. REITs: P/FFO, P/AFFO. Pharma: EV/EBITDA with pipeline-adjusted metrics.",category:"Valuation",firm:"Morgan Stanley, Citi",difficulty:"Medium"},
{q:"Why might EV/EBITDA be preferred to EV/EBIT for some sectors and the opposite for others?",a:"EV/EBITDA works well for comparing companies with different D&A policies or capital structures. EV/EBIT is better for capital-intensive businesses where D&A represents a real cost of maintaining assets — ignoring it would overstate cash generation.",category:"Valuation",firm:"Evercore",difficulty:"Medium"},
{q:"Explain why equity value-based multiples and enterprise value-based multiples capture different things.",a:"EV multiples (EV/EBITDA, EV/Revenue) measure the value of the entire firm relative to pre-financing metrics — capital structure neutral. Equity multiples (P/E, P/BV) measure value to equity holders relative to post-interest metrics. Mixing them (e.g., EV/NI) is a mismatch.",category:"Valuation",firm:"J.P. Morgan, Lazard",difficulty:"Medium"},
{q:"What adjustments do you make to enterprise value to arrive at an adjusted firm value suitable for multiples?",a:"Start with equity value (market cap). Add debt, preferred stock, minority interest. Subtract cash and equivalents. May also add unfunded pensions, capitalize operating leases, add contingent liabilities. Subtract equity investments or non-operating assets valued separately.",category:"Valuation",firm:"Centerview Partners, Goldman Sachs",difficulty:"Medium"},
{q:"How do you value a company with negative EBITDA using market-based methods?",a:"Use EV/Revenue as the primary multiple. Also consider forward multiples if profitability is expected. User/subscriber-based metrics for tech (EV/subscriber, EV/GMV). DCF with explicit path to profitability. Comparable transaction multiples from recent deals in the space.",category:"Valuation",firm:"Morgan Stanley, Moelis & Co.",difficulty:"Medium"},
{q:"What are some pitfalls of relying on headline P/E ratios when comparing companies?",a:"P/E is distorted by capital structure (leverage inflates EPS), tax rate differences, non-recurring items, different share count methodologies, and accounting policy choices. Two companies with identical operations but different leverage will show very different P/Es.",category:"Valuation",firm:"Barclays, UBS",difficulty:"Medium"},
{q:"How would you normalize earnings for a cyclical business before applying trading multiples?",a:"Use mid-cycle or through-cycle average earnings rather than peak or trough. Look at 5-10 year average margins and apply them to current revenue. Alternatively, use normalized EBITDA based on average utilization rates or commodity prices.",category:"Valuation",firm:"Lazard, Rothschild",difficulty:"Hard"},
{q:"Why might you exclude certain outlier companies when constructing a trading comps set?",a:"If a comp has extreme multiples due to distress, pending M&A, one-time events, or vastly different growth profile, it can skew the range and mislead the analysis. Exclude with explanation, but show the full set for transparency.",category:"Valuation",firm:"Evercore",difficulty:"Easy"},
{q:"How do you calendarize financials to ensure consistency across companies with different fiscal year-ends?",a:"Weight financials proportionally. For a company with a March FY end, the calendar year estimate blends 75% of the March FY and 25% of the next March FY. This ensures all comps are on the same time basis for fair comparison.",category:"Valuation",firm:"Goldman Sachs, J.P. Morgan",difficulty:"Medium"},
{q:"Explain the logic behind using forward rather than trailing multiples in some sectors.",a:"Forward multiples reflect where the market expects the company to be, not where it has been. This matters more for high-growth companies or sectors undergoing rapid change. Markets are forward-looking, so forward multiples better capture current pricing.",category:"Valuation",firm:"Morgan Stanley",difficulty:"Easy"},
{q:"What are the advantages and disadvantages of precedent transaction analysis versus trading comparables?",a:"Precedents reflect actual prices paid including control premiums and synergies — realistic for M&A. But they may be stale (different market conditions), have limited data, and premiums vary widely. Comps are current but reflect minority value without control premium.",category:"Valuation",firm:"PJT Partners, Centerview Partners",difficulty:"Medium"},
{q:"How do you select relevant precedent transactions for valuing a target in a sale process?",a:"Screen for: same or similar industry, comparable size, similar time period (ideally last 3-5 years), similar deal type (strategic vs financial buyer), and geographic relevance. Adjust for market conditions if comparing across different rate environments.",category:"Valuation",firm:"Houlihan Lokey, Lazard",difficulty:"Medium"},
{q:"Why do precedent transactions often imply higher valuation multiples than trading comparables?",a:"Because acquisition prices include a control premium (20-40% typical), expected synergies, scarcity value in competitive auctions, and strategic motivations. Trading comps reflect minority, uncontrolled share prices without these premiums.",category:"Valuation",firm:"Goldman Sachs, Evercore",difficulty:"Easy"},
{q:"Walk through a simple DCF from revenue to valuation output.",a:"Project revenue → operating expenses → EBIT → tax-effect → add back D&A → subtract CapEx → subtract WC changes = UFCF. Discount each year's UFCF at WACC. Calculate terminal value and discount it back. Sum all PVs = Enterprise Value. Subtract net debt = Equity Value. Divide by diluted shares = per share value.",category:"Valuation",firm:"J.P. Morgan, Morgan Stanley, Goldman Sachs",difficulty:"Medium"},
{q:"What are the key drivers of free cash flow in a standard corporate DCF?",a:"Revenue growth rate, operating margins (EBIT margin), tax rate, depreciation and amortization, capital expenditures, and working capital changes. Terminal value assumptions (growth rate or exit multiple) also dominate the output.",category:"Valuation",firm:"Evercore, Centerview Partners",difficulty:"Easy"},
{q:"Why is the free cash flow to firm (unlevered) approach common in banking DCF work?",a:"UFCF is capital-structure neutral — it values the entire firm before financing decisions. This allows comparison across companies with different leverage, and WACC accounts for the blended cost of all capital. It separates operating value from financing value.",category:"Valuation",firm:"Goldman Sachs, Lazard",difficulty:"Medium"},
{q:"Define the formula for unlevered free cash flow starting from EBIT.",a:"UFCF = EBIT × (1 − Tax Rate) + D&A − CapEx − Change in Net Working Capital. This captures cash generated by operations available to all capital providers (debt and equity) before any financing costs.",category:"Valuation",firm:"J.P. Morgan, Bank of America",difficulty:"Easy"},
{q:"What is WACC conceptually, and why is it used as the discount rate in an unlevered DCF?",a:"WACC is the weighted average return required by all capital providers (debt and equity), weighted by their proportion of the capital structure. Since UFCF belongs to all providers, WACC is the appropriate rate to discount it — it reflects the blended cost of financing the entire firm.",category:"Valuation",firm:"Morgan Stanley, PJT Partners",difficulty:"Medium"},
{q:"Walk through the calculation of WACC and the main inputs required.",a:"WACC = (E/V) × Cost of Equity + (D/V) × Cost of Debt × (1−T). Inputs: market cap (E), net debt (D), total firm value (V=E+D), cost of equity (CAPM), pre-tax cost of debt (yield on existing debt or new issuance), and marginal tax rate (T).",category:"Valuation",firm:"Goldman Sachs, Evercore",difficulty:"Medium"},
{q:"Explain how to estimate the cost of equity using CAPM and the intuition behind each term.",a:"Cost of Equity = Risk-Free Rate + Beta × Equity Risk Premium. Risk-free rate: time value of money (10-year Treasury). Beta: sensitivity to market risk. ERP: extra return investors demand for stocks over bonds. Together: the return equity investors require for bearing this company's risk.",category:"Valuation",firm:"Centerview Partners, J.P. Morgan",difficulty:"Medium"},
{q:"How do you estimate beta for a private company using public comparables?",a:"Get observed (levered) betas for public comps. Unlever each using their D/E ratios to isolate business risk. Take the median unlevered beta. Relever at the target's assumed capital structure. This gives a beta reflecting the target's business risk and financing.",category:"Valuation",firm:"Lazard, Morgan Stanley",difficulty:"Hard"},
{q:"Explain why you unlever and then relever beta when estimating cost of equity.",a:"Observed betas include both business risk and financial risk (leverage). To compare business risk across companies, you must strip out leverage effects (unlever). Then you relever for the target's specific capital structure to get the appropriate beta for that company's financing.",category:"Valuation",firm:"Goldman Sachs, Evercore",difficulty:"Hard"},
{q:"Describe the two main approaches to estimating terminal value.",a:"1) Gordon Growth (Perpetuity): TV = Final Year FCF × (1+g) / (WACC−g). Assumes the business grows at a constant rate forever. 2) Exit Multiple: TV = Final Year EBITDA × Exit Multiple. Applies a market-based multiple to terminal year earnings. Both should be cross-checked.",category:"Valuation",firm:"J.P. Morgan, Centerview Partners",difficulty:"Medium"},
{q:"When would you favor a perpetuity growth terminal value versus an exit multiple approach?",a:"Perpetuity growth is more theoretically grounded for stable, mature businesses. Exit multiple is more market-anchored and intuitive for bankers. In practice, most analysts use exit multiple as primary and perpetuity growth as a cross-check to validate the implied growth rate.",category:"Valuation",firm:"Morgan Stanley, Lazard",difficulty:"Medium"},
{q:"How do you choose an appropriate long-term growth rate in a Gordon Growth terminal value?",a:"It should approximate long-term nominal GDP growth (2-3% for developed markets). It should not exceed the economy's growth rate because no company can grow faster than the economy indefinitely. Consider the company's industry growth and competitive position within that range.",category:"Valuation",firm:"Goldman Sachs, PJT Partners",difficulty:"Medium"},
{q:"What are some indicators that your DCF output is overly dependent on the terminal value?",a:"If terminal value represents more than 75-80% of total enterprise value, the explicit forecast period is adding little information. This suggests either the forecast period is too short, the terminal growth rate is too aggressive, or the exit multiple is too high.",category:"Valuation",firm:"Evercore, Bank of America",difficulty:"Medium"},
{q:"Describe how you would value a bank differently from a traditional industrial company.",a:"Banks use deposits as operational funding (not traditional debt), so EV/EBITDA doesn't work. Use equity-based metrics: P/E, P/TBV, dividend discount model, or residual income model. Focus on ROE, NIM, credit quality, and capital ratios rather than EBITDA.",category:"Valuation",firm:"Goldman Sachs, J.P. Morgan, Morgan Stanley",difficulty:"Hard"},
{q:"How would you value an early-stage high-growth technology company with minimal earnings?",a:"EV/Revenue multiples using comparable high-growth companies. DCF with explicit path to profitability (model margin expansion over time). Comparable transactions from recent funding rounds or acquisitions. Unit economics analysis (LTV/CAC). TAM/SAM/SOM framework for market sizing.",category:"Valuation",firm:"Moelis & Co., Centerview Partners",difficulty:"Hard"},
{q:"Describe a sum-of-the-parts valuation and when it is most applicable.",a:"Value each business segment separately using the most appropriate methodology and peer set for each. Sum the segment values, add corporate-level assets, subtract corporate overhead and net debt. Most useful for conglomerates or companies with distinct business lines trading at a discount.",category:"Valuation",firm:"Lazard, Evercore",difficulty:"Medium"},
{q:"How does an LBO analysis help a strategic buyer decide its maximum bid in an auction?",a:"The LBO sets a valuation floor — the maximum a financial sponsor would pay while achieving target returns. A strategic buyer should be willing to pay at least this much (since they have synergies) but the LBO provides a reference for how competitive the auction will be.",category:"Valuation",firm:"Goldman Sachs, PJT Partners",difficulty:"Medium"},
{q:"How do changes in the risk-free rate affect both DCF valuation and multiples?",a:"Higher risk-free rate → higher WACC → lower PV of cash flows → lower DCF value. It also compresses trading multiples as investors demand higher returns. The effect is larger for long-duration growth stocks where more value sits in distant future cash flows.",category:"Valuation",firm:"Morgan Stanley, J.P. Morgan",difficulty:"Medium"},
{q:"Explain the rationale for using enterprise value rather than equity value in most trading multiples.",a:"EV captures the value of the entire business to all capital providers, making it independent of capital structure. This allows fair comparison of companies with different leverage. EV paired with pre-interest metrics (EBITDA, Revenue) avoids the distortion that debt creates in equity-only metrics.",category:"Valuation",firm:"Evercore, Goldman Sachs",difficulty:"Easy"},
{q:"How do you treat capitalized operating leases when computing enterprise value and EBITDA multiples?",a:"Add the present value of operating lease obligations to EV (they're debt-like). Add back the lease expense to EBITDA (since the obligation is now in EV). This ensures numerator and denominator are consistent and comparable across companies with different lease vs own decisions.",category:"Valuation",firm:"Bank of America, Lazard",difficulty:"Hard"},
{q:"How do you incorporate scenario analysis into a DCF framework?",a:"Build base, bull, and bear cases with different assumptions for growth, margins, CapEx, and terminal value. Probability-weight the scenarios (e.g., 25% bull, 50% base, 25% bear) and compute a weighted-average valuation. Present the range to show risk-reward distribution.",category:"Valuation",firm:"Centerview Partners, PJT Partners",difficulty:"Medium"},
{q:"What is the logic behind using mid-year discounting in a DCF, and when do you apply it?",a:"Mid-year convention assumes cash flows arrive evenly throughout each year rather than at year-end. It shifts discount factors back by half a year, slightly increasing present values. Used for most corporate DCFs; year-end convention may be used for seasonal businesses.",category:"Valuation",firm:"Goldman Sachs, Morgan Stanley",difficulty:"Medium"},
{q:"What are the most common errors junior analysts make when building DCFs?",a:"Mismatching EV and equity value metrics, incorrect WACC components, terminal growth rate exceeding GDP, not discounting terminal value, using book values instead of market values in WACC, circular references not resolved, inconsistent tax rates, and not sanity-checking output vs market.",category:"Valuation",firm:"J.P. Morgan, Evercore",difficulty:"Medium"},
];

